### Django DB router (simplified)

# routes queries to a Postgres shard based on user_id

class UserShardRouter:
    def db_for_write(self, model, **hints):
        user_id = hints.get('user_id')
        if user_id is None:
            return 'default'
        shard = self._shard_for_user(user_id)
        return f'postgres_shard_{shard}'

    def db_for_read(self, model, **hints):
        user_id = hints.get('user_id')
        if user_id is None:
            return 'default'
        shard = self._shard_for_user(user_id)
        return f'postgres_shard_{shard}'

    def _shard_for_user(self, user_id):
        # simple modulo-based sharding
        return user_id % 16  # 16 shards

# Usage in code when saving an object:
# MyModel.objects.using(router.db_for_write(MyModel, user_id=12345)).create(...)
